PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(MAX(?attendance) AS ?maxAttendance) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?series wdt:P31 wd:Q191196 ; wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840 ; wdt:P585 ?date .
  FILTER(YEAR(?date) = ?year)
  ?series wdt:P527 ?game .
  ?game wdt:P1110 ?attendance .
}

